/**
 * @migrated-from src/lib/components/layout/RightSidebar.svelte
 * @source-hash sha256:b9d05589604ae5dcaf05f4a435278f78e23cc55de7ceb32c3700829f419adf90
 * @features panels-toolbar-shell,startup-window-cli-lifecycle,theme-background-empty-state
 * @source-disposition manual
 * @migration-status partial-scaffold
 * @unsupported attribute BindDirective; attribute ClassDirective; template node ConstTag; template node SnippetBlock
 * Generated by @xiranite/svelte-migrate; move to production only after behavior tests pass.
 */
import { Fragment } from "react"
import {
		Pin,
		PinOff,
		GripVertical,
		GripHorizontal,
		MousePointer2,
		ArrowDownLeft
	} from 'lucide-react';
import MagicCard from '$lib/components/ui/MagicCard.js';
import {
		activeRightPanel,
		setActiveRightPanel,
		rightSidebarWidth,
		rightSidebarPinned,
		rightSidebarLockState,
		rightSidebarOpen,
		sidebarRightPanels,
		sidebarConfigStore,
		rightSidebarVerticalAlign,
		rightSidebarHorizontalPos,
		rightSidebarHeight,
		rightSidebarCustomHeight,
		enableBlankAreaCollapse,
		blankAreaCollapseMode,
		showDragHandle,
		type PanelId
	} from '$lib/stores';
import * as Sidebar from '$lib/components/ui/sidebar';
import { PANEL_COMPONENTS } from '$lib/components/panels';
import { Button } from '$lib/components/ui/button';
import HoverWrapper from './HoverWrapper.js';
import { settingsManager } from '$lib/settings/settingsManager';
import Icon from '$lib/components/ui/Icon.js';
interface Props {
		onResize?: (width: number) => void;
	}

export function RightSidebar(props: Props) {
  const { onResize } = props
  let isVisible = $state($rightSidebarOpen);

  let localRightSidebarOpen = $state($rightSidebarOpen);

  let settings = $state(settingsManager.getSettings());

  let autoHideTiming = $derived(
      settings.panels?.autoHideTiming ?? { showDelaySec: 0, hideDelaySec: 0 }
    );

  let rightPanels = $derived($sidebarRightPanels);

  let activePanelId = $state<PanelId>('info');

  const panelComponents = PANEL_COMPONENTS;

  let isResizing = $state(false);

  let startX = 0;

  let startWidth = 0;

  function handleMouseDown(e: MouseEvent) {
      // console.log('[RightSidebar] handleMouseDown called', e.clientX, $rightSidebarWidth);
      isResizing = true;
      startX = e.clientX;
      startWidth = $rightSidebarWidth;
      e.preventDefault();
    }

  function handleMouseMove(e: MouseEvent) {
      if (!isResizing) return;

      const delta = startX - e.clientX; // 右侧边栏，向左拖拽时delta为正（增加宽度）
      const newWidth = Math.max(200, Math.min(600, startWidth + delta));

      // console.log('[RightSidebar] handleMouseMove', {
      //   clientX: e.clientX,
      //   startX,
      //   delta,
      //   startWidth,
      //   newWidth
      // });

      rightSidebarWidth.set(newWidth);
      onResize?.(newWidth);
    }

  function handleMouseUp() {
      // console.log('[RightSidebar] handleMouseUp called, isResizing was:', isResizing);
      isResizing = false;
    }

  let isDragging = $state(false);

  let dragStartX = 0;

  let dragStartY = 0;

  let initialXPos = 0;

  let initialYPos = 0;

  function handleDragStart(e: PointerEvent) {
      if ($rightSidebarHeight === 'full') return; // 全高模式不允许拖拽
      isDragging = true;
      dragStartX = e.clientX;
      dragStartY = e.clientY;
      initialXPos = $rightSidebarHorizontalPos;
      initialYPos = $rightSidebarVerticalAlign;
      (e.target as HTMLElement).setPointerCapture(e.pointerId);
      e.preventDefault();
    }

  function handleDragMove(e: PointerEvent) {
      if (!isDragging) return;

      const deltaX = e.clientX - dragStartX;
      const deltaY = e.clientY - dragStartY;

      // 转换为百分比 (右侧边栏 X 轴反向)
      const xDeltaPercent = (deltaX / window.innerWidth) * -200; // 负号因为右侧边栏左移=增加偏移
      const yDeltaPercent = (deltaY / window.innerHeight) * 200;

      const newXPos = Math.max(0, Math.min(100, initialXPos + xDeltaPercent));
      const newYPos = Math.max(0, Math.min(100, initialYPos + yDeltaPercent));

      sidebarConfigStore.setRightSidebarHorizontalPos(newXPos);
      sidebarConfigStore.setRightSidebarVerticalAlign(newYPos);
    }

  function handleDragEnd(e: PointerEvent) {
      if (isDragging) {
        isDragging = false;
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
      }
    }

  let isCornerResizing = $state(false);

  let cornerStartX = 0;

  let cornerStartY = 0;

  let cornerStartWidth = 0;

  let cornerStartHeight = 0;

  function handleCornerResizeStart(e: PointerEvent) {
      isCornerResizing = true;
      cornerStartX = e.clientX;
      cornerStartY = e.clientY;
      cornerStartWidth = $rightSidebarWidth;
      cornerStartHeight = $rightSidebarHeight === 'full' ? 100 : $rightSidebarCustomHeight;

      // 如果是全高模式开始缩放，先切换到自定义模式
      if ($rightSidebarHeight === 'full') {
        sidebarConfigStore.setRightSidebarHeight('custom');
        sidebarConfigStore.setRightSidebarCustomHeight(100);
      }

      (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
      e.preventDefault();
      e.stopPropagation();
    }

  function handleCornerResizeMove(e: PointerEvent) {
      if (!isCornerResizing) return;

      // 宽度调整 (右侧边栏向左拖拽增加宽度)
      const deltaX = cornerStartX - e.clientX;
      const newWidth = Math.max(200, Math.min(600, cornerStartWidth + deltaX));
      rightSidebarWidth.set(newWidth);
      onResize?.(newWidth);

      // 高度调整
      const deltaY = e.clientY - cornerStartY;
      const deltaHeightPercent = (deltaY / window.innerHeight) * 100;
      const newHeight = Math.max(10, Math.min(100, cornerStartHeight + deltaHeightPercent));

      if (newHeight >= 99.5) {
        sidebarConfigStore.setRightSidebarHeight('full');
        sidebarConfigStore.setRightSidebarCustomHeight(100);
      } else {
        sidebarConfigStore.setRightSidebarHeight('custom');
        sidebarConfigStore.setRightSidebarCustomHeight(newHeight);
      }
    }

  function handleCornerResizeEnd(e: PointerEvent) {
      if (isCornerResizing) {
        isCornerResizing = false;
        (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId);
      }
    }

  function togglePin() {
      rightSidebarPinned.set(!$rightSidebarPinned);
    }

  function handlePinContextMenu(e: MouseEvent) {
      e.preventDefault();
      collapseSidebar();
    }

  function collapseSidebar() {
      rightSidebarPinned.set(false);
      localRightSidebarOpen = false;
      rightSidebarOpen.set(false);
    }

  function isInteractiveElement(target: EventTarget | null): boolean {
      if (!(target instanceof HTMLElement)) return false;
      // 空白收回按钮本身放行，不当作交互元素过滤
      if (target.closest('[data-blank-collapse="true"]')) return false;
      return Boolean(
        target.closest(
          'button,a,input,textarea,select,label,[role="button"],[role="switch"],[data-sidebar="menu-button"]'
        )
      );
    }

  function handleBlankAreaClick(e: MouseEvent) {
      if (!$enableBlankAreaCollapse || $blankAreaCollapseMode !== 'single') return;
      if (isInteractiveElement(e.target)) return;
      collapseSidebar();
    }

  function handleBlankAreaDoubleClick(e: MouseEvent) {
      if (!$enableBlankAreaCollapse || $blankAreaCollapseMode !== 'double') return;
      if (isInteractiveElement(e.target)) return;
      collapseSidebar();
    }

  function handleVisibilityChange(visible: boolean) {
      // 锁定隐藏时，不响应悬停
      if ($rightSidebarLockState === false) return;
      if (!$rightSidebarPinned && $rightSidebarLockState !== true) {
        localRightSidebarOpen = visible;
        rightSidebarOpen.set(visible);
      }
    }

  function handleTabChange(panelId: PanelId) {
      activePanelId = panelId;
      // 设置活动面板
      setActiveRightPanel(panelId as any);
    }

  $effect(() => {
      if ($activeRightPanel && rightPanels.some((p) => p.id === $activeRightPanel)) {
        activePanelId = $activeRightPanel as PanelId;
      }
    });

  $effect(() => {
      // 锁定隐藏时，强制关闭
      if ($rightSidebarLockState === false) {
        localRightSidebarOpen = false;
        rightSidebarOpen.set(false);
        return;
      }
      // 锁定显示或钉住时，强制打开
      if ($rightSidebarPinned || $rightSidebarLockState === true) {
        localRightSidebarOpen = true;
        rightSidebarOpen.set(true);
      }
    });

  $effect(() => {
      localRightSidebarOpen = $rightSidebarOpen;
    });

  $effect(() => {
      // console.log('[RightSidebar] Setting up global mouse event listeners');
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);

      return () => {
        // console.log('[RightSidebar] Cleaning up global mouse event listeners');
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
      };
    });

  settingsManager.addListener((next) => {
      settings = next;
    });
  return (
    <Fragment>

<HoverWrapper pinned={$rightSidebarPinned} onVisibilityChange={handleVisibilityChange} hideDelay={autoHideTiming.hideDelaySec * 1000} showDelay={autoHideTiming.showDelaySec * 1000} side="right">
	<div className="relative flex h-full" style={`--sidebar-width: ${$rightSidebarWidth}px; width: ${$rightSidebarWidth}px;`}>
		<div className="flex min-h-0 flex-1">
			<Sidebar.Provider onOpenChange={(v) => {
					localRightSidebarOpen = v;
					rightSidebarOpen.set(v);
				}} style={`--sidebar-width: ${$rightSidebarWidth}px;`}>
				<Sidebar.Root side="right" collapsible="offcanvas" className="overflow-hidden [&>[data-sidebar=sidebar]]:flex-row-reverse">
					{/*  一级菜单 - 图标模式  */}
					<MagicCard className="h-full !w-[calc(var(--sidebar-width-icon)_+_1px)]" gradientSize={80} gradientOpacity={0.4}>
						<Sidebar.Root collapsible="none" className="h-full !w-[calc(var(--sidebar-width-icon)_+_1px)]" style="width: calc(var(--sidebar-width-icon) + 1px);">
							<Sidebar.Header className="flex flex-col gap-2 px-1.5 py-2">
								<div className="flex flex-col gap-1">
									<Button variant={$rightSidebarPinned ? 'default' : 'ghost'} size="icon" className="h-9 w-9" onClick={togglePin} onContextmenu={handlePinContextMenu}>
										{$rightSidebarPinned ? (<Fragment>
											<PinOff className="h-4 w-4"></PinOff>
										</Fragment>) : (<Fragment>
											<Pin className="h-4 w-4"></Pin>
										</Fragment>)}
									</Button>
									{/*  拖拽移动按钮  */}
									{$showDragHandle && $rightSidebarHeight !== 'full' ? (<Fragment>
										<button type="button" className={`flex h-9 w-9 cursor-move items-center justify-center rounded-md transition-colors
											${isDragging
												? 'bg-primary text-primary-foreground'
												: 'hover:bg-accent text-muted-foreground hover:text-foreground'}`} onPointerDown={handleDragStart} onPointerMove={handleDragMove} onPointerUp={handleDragEnd} onPointercancel={handleDragEnd} title="拖拽移动侧边栏">
											<MousePointer2 className="h-4 w-4"></MousePointer2>
										</button>
									</Fragment>) : null}
								</div>
							</Sidebar.Header>

							<Sidebar.Content>
								<Sidebar.Group>
									<Sidebar.GroupContent className="flex h-full min-h-0 flex-col px-0">
										<Sidebar.Menu>
											{rightPanels.map((panel) => (<Fragment key={panel.id}>
												<Sidebar.MenuItem>
													<Sidebar.MenuButton tooltipContentProps={{
															hidden: false
														}} onClick={() => handleTabChange(panel.id)} isActive={activePanelId === panel.id} className="px-2">
														{/* TODO unsupported SnippetBlock */}
														<Icon name={panel.id} fallback={panel.icon} className="h-4 w-4"></Icon>
														<span>{panel.title}</span>
													</Sidebar.MenuButton>
												</Sidebar.MenuItem>
											</Fragment>))}
										</Sidebar.Menu>
										<button type="button" className="min-h-0 w-full flex-1 bg-transparent" data-blank-collapse="true" onClick={handleBlankAreaClick} onDoubleClick={handleBlankAreaDoubleClick} aria-label="收回右侧边栏"></button>
									</Sidebar.GroupContent>
								</Sidebar.Group>
							</Sidebar.Content>
						</Sidebar.Root>
					</MagicCard>

					{/*  二级菜单 - 内容面板  */}
					<Sidebar.Root collapsible="none" className="flex flex-1" style="width: calc(var(--sidebar-width) - var(--sidebar-width-icon) - 1px);">
						<Sidebar.Content className="h-full">
							<Sidebar.Group className="h-full flex-1 p-0">
								<Sidebar.GroupContent className="h-full">
									{/*  使用 content-visibility: hidden 保持布局信息，避免切换时重新计算尺寸  */}
									{rightPanels.map((panel) => (<Fragment key={panel.id}>
										{/* TODO unsupported ConstTag */}
										{PanelComponent ? (<Fragment>
											<div className="panel-content-wrapper">
												<PanelComponent></PanelComponent>
											</div>
										</Fragment>) : null}
									</Fragment>))}
								</Sidebar.GroupContent>
							</Sidebar.Group>
						</Sidebar.Content>
					</Sidebar.Root>

					{/*  拖拽手柄  */}
					<button type="button" className="hover:bg-accent text-muted-foreground absolute top-1/2 left-0 z-60 -translate-y-1/2 cursor-ew-resize rounded-r-md p-1 opacity-0 transition-all hover:opacity-100" onMouseDown={handleMouseDown} onContextmenu={handlePinContextMenu} aria-label="调整右侧边栏宽度">
						<GripVertical className="h-4 w-4"></GripVertical>
					</button>

					{/*  边角缩放手柄 (左下角)  */}
					{$rightSidebarHeight !== 'full' ? (<Fragment>
						<button type="button" className={`text-muted-foreground/30 hover:text-primary absolute bottom-0 left-0 z-[60] cursor-nesw-resize p-1 transition-colors
							${isCornerResizing ? 'text-primary' : ''}`} onPointerDown={handleCornerResizeStart} onPointerMove={handleCornerResizeMove} onPointerUp={handleCornerResizeEnd} onPointercancel={handleCornerResizeEnd} aria-label="同时调整侧边栏宽高">
							<ArrowDownLeft className="h-4 w-4"></ArrowDownLeft>
						</button>
					</Fragment>) : null}
				</Sidebar.Root>
			</Sidebar.Provider>
		</div>
	</div>
</HoverWrapper>

</Fragment>
  )
}
